 // verify that account creation is unsuccessful when registered user email is entered in the registration form
test('verify that account creation is unsuccessful when a registered user email is entered in the registration form', async ({ page })  => {

  await page.goto('https://demo.evershop.io/');

    // click the account link in the nav bar to navigate to the login page
  await page.getByRole('link').nth(3).click();

    // click the "Create an account" link to navigate to the registration page
  await page.getByRole('link', { name: 'Create an account' }).click();

  await page.waitForLoadState('domcontentloaded')

    // fill out the registration form with valid information
  await page.getByRole('textbox', { name: 'Full Name *' }).click();
  await page.getByRole('textbox', { name: 'Full Name *' }).fill('Joseph Ogunsuada');
  await page.getByRole('textbox', { name: 'Email *' }).click();
  await page.getByRole('textbox', { name: 'Email *' }).fill('josephogunsuada@gmail.com');
  await page.getByRole('textbox', { name: 'Password *' }).click();
  await page.getByRole('textbox', { name: 'Password *' }).fill('ogunsuada');

   // click the "Sign Up" button to submit the registration form
  await page.getByRole('button', { name: 'Sign Up' }).click();

  await page.waitForLoadState('domcontentloaded')
  
    // Assert that the error message "Email is already used" is visible
  await page.waitForSelector('text=Email is already used', { timeout: 15000 });
await expect(page.getByText('Email is already used')).toBeVisible();
});



