  //E2E TESTING SCENARIO: Verify that a user can successfully add a product to the cart and proceed to checkout
test('verify that a user can successfully add a product to the cart and proceed to checkout', async ({ page }) => { 
  
    // Navigate to the homepage
  await page.goto('https://demo.evershop.io/');

    // Click on the first featured product which is the "Stainless Steel Thermos - Yellow"
  await page.getByRole('link', { name: 'Stainless Steel Thermos - Yellow Stainless Steel Thermos - Yellow $' }).click();

    //Select an available color option for the product
    await page.goto('https://demo.evershop.io/accessories/stainless-steel-thermos-yellow?color=3', { waitUntil: 'domcontentloaded' });

    // Click the "Add to Cart" button on the product page
  await page.getByRole('button', { name: 'ADD TO CART' }).click();  

    // Assert that the cart dialog is visible 
  await expect(page.getByRole('heading', { name: 'Your Cart' })).toBeVisible();

    // Click the "Checkout" button in the cart dialog
  await page.getByRole('button', { name: 'Checkout' }).click(); 

    // Assert that the URL is exactly what you expect for the checkout page
  await expect(page).toHaveURL('https://demo.evershop.io/checkout');
});




